/**
 * ResourceUsage — shows resources with their task assignments
 * and work distribution in a timeline grid.
 */

import React, { useMemo } from 'react';
import {
  Box,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  TableContainer,
  Typography,
  Collapse,
} from '@mui/material';
import ExpandMoreIcon from '@mui/icons-material/ExpandMore';
import ChevronRightIcon from '@mui/icons-material/ChevronRight';

import { useProjectStore, type ResourceRow, type AssignmentRow, type TaskRow } from '../../stores';
import { durationDays } from '../../utils/format';

interface ResourceGroup {
  resource: ResourceRow;
  assignments: (AssignmentRow & { taskName: string; taskDuration: number })[];
  totalWork: number;
}

const ResourceUsage: React.FC = () => {
  const resources = useProjectStore((s) => s.resources);
  const assignments = useProjectStore((s) => s.assignments);
  const tasks = useProjectStore((s) => s.tasks);

  const [expandedIds, setExpandedIds] = React.useState<Set<string>>(
    () => new Set(resources.map((r) => r.id)),
  );

  const toggleExpand = (id: string) => {
    setExpandedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const taskMap = useMemo(
    () => new Map(tasks.map((t) => [t.id, t])),
    [tasks],
  );

  const groups: ResourceGroup[] = useMemo(() => {
    return resources.map((res) => {
      const resAssignments = assignments
        .filter((a) => a.resourceId === res.id)
        .map((a) => {
          const task = taskMap.get(a.taskId);
          return {
            ...a,
            taskName: task?.name ?? 'Unknown',
            taskDuration: task?.durationMinutes ?? 0,
          };
        });
      const totalWork = resAssignments.reduce((s, a) => s + a.workMinutes, 0);
      return { resource: res, assignments: resAssignments, totalWork };
    });
  }, [resources, assignments, taskMap]);

  if (resources.length === 0) {
    return (
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
        <Typography color="text.secondary">No resources defined.</Typography>
      </Box>
    );
  }

  return (
    <TableContainer sx={{ height: '100%', overflow: 'auto' }}>
      <Table size="small" stickyHeader sx={{ tableLayout: 'fixed' }}>
        <TableHead>
          <TableRow>
            <TableCell sx={{ width: 40 }} />
            <TableCell sx={{ minWidth: 200 }}>Resource / Task Name</TableCell>
            <TableCell sx={{ width: 80 }}>Type</TableCell>
            <TableCell sx={{ width: 100 }} align="right">
              Work
            </TableCell>
            <TableCell sx={{ width: 80 }} align="right">
              Units
            </TableCell>
            <TableCell sx={{ width: 100 }} align="right">
              Duration
            </TableCell>
          </TableRow>
        </TableHead>
        <TableBody>
          {groups.map((g) => (
            <React.Fragment key={g.resource.id}>
              {/* Resource row */}
              <TableRow
                hover
                onClick={() => toggleExpand(g.resource.id)}
                sx={{ cursor: 'pointer', bgcolor: '#F5F5F5' }}
              >
                <TableCell>
                  {g.assignments.length > 0 && (
                    expandedIds.has(g.resource.id) ? (
                      <ExpandMoreIcon sx={{ fontSize: 16 }} />
                    ) : (
                      <ChevronRightIcon sx={{ fontSize: 16 }} />
                    )
                  )}
                </TableCell>
                <TableCell>
                  <Typography sx={{ fontWeight: 700, fontSize: '0.8125rem' }}>
                    {g.resource.name}
                  </Typography>
                </TableCell>
                <TableCell>
                  {String(g.resource.type).charAt(0).toUpperCase() +
                    String(g.resource.type).slice(1)}
                </TableCell>
                <TableCell align="right">
                  {durationDays(g.totalWork)}
                </TableCell>
                <TableCell align="right">
                  {g.resource.maxUnits}%
                </TableCell>
                <TableCell />
              </TableRow>

              {/* Assignment rows */}
              {expandedIds.has(g.resource.id) &&
                g.assignments.map((a) => (
                  <TableRow key={a.id} hover sx={{ bgcolor: '#FAFAFA' }}>
                    <TableCell />
                    <TableCell sx={{ pl: 4 }}>
                      <Typography sx={{ fontSize: '0.8125rem' }}>
                        {a.taskName}
                      </Typography>
                    </TableCell>
                    <TableCell />
                    <TableCell align="right">
                      {durationDays(a.workMinutes)}
                    </TableCell>
                    <TableCell align="right">{a.units}%</TableCell>
                    <TableCell align="right">
                      {durationDays(a.taskDuration)}
                    </TableCell>
                  </TableRow>
                ))}
            </React.Fragment>
          ))}
        </TableBody>
      </Table>
    </TableContainer>
  );
};

export default ResourceUsage;
